import {HTTPClient, WSClient} from 'jibo-client-framework';
import {EventEmitter} from "events";

class NotificationsService extends EventEmitter {
    constructor(){
        super();
    }

    init(service, cb){
        console.log('notifications-service');
        this.httpClient = new HTTPClient('127.0.0.1', service.port);
        this.wsClient = new WSClient('ws://' + '127.0.0.1' + ':' + service.port);

        this.wsClient.on('open', () => {
            cb();
        });

        this.wsClient.on('message', (message) => {
            this.emit(message.eventName, message.event);
        });
    }

    /*
     * Add a basic 'message' notification to the notifications queue for this skill
     */
    create(notification, cb){
        this.httpClient.sendRequest('POST', '/notifications', JSON.stringify(notification), cb);
    }

    /*
     * Update a notification. Any field provide overrides the existing one, other wise
     * fields are left unchanged.
     */
    update(id, notificationChanges, cb){
        this.httpClient.sendRequest('PUT', `/notifications/${id}`, JSON.stringify(notificationChanges), cb);
    }

    /*
     * Get all notification
     */
    getAll(cb){
        this.httpClient.sendRequest('GET', '/notifications', '{}', cb);
    }

    /*
     * Delete a notification
     */
    delete(id, cb){
        this.httpClient.sendRequest('DELETE', `/notifications/${id}`, '{}', cb);
    }

    /*
     * Delete all notifications
     */
    deleteAll(cb){
        this.httpClient.sendRequest('DELETE', `/notifications`, '{}', cb);
    }
}

export default NotificationsService;
